        AtomicInteger counter = new AtomicInteger(2);



        Mockito.when(service.verySlowMethod()).thenAnswer(new LockingAnswer(counter));



        threads.execute(new ServiceRunner(service));
        threads.execute(new ServiceRunner(service));



        threads.shutdown();

